CREATE OR REPLACE FUNCTION docs.get_charte(p_id text)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_c docs.charte;
  v_body text;
  v_k text;
  v_v text;
BEGIN
  SELECT * INTO v_c FROM docs.charte WHERE id = p_id AND tenant_id = current_setting('app.tenant_id', true);
  IF v_c IS NULL THEN RETURN pgv.empty(pgv.t('docs.err_charte_not_found')); END IF;

  v_body := pgv.breadcrumb(VARIADIC ARRAY[pgv.t('docs.brand'), '/chartes', pgv.esc(v_c.name)]);

  IF v_c.description IS NOT NULL THEN
    v_body := v_body || '<p>' || pgv.esc(v_c.description) || '</p>';
  END IF;

  -- Colors
  v_body := v_body || '<h3>Couleurs</h3>'
    || pgv.grid(VARIADIC ARRAY[
      pgv.stat('Background', pgv.badge(v_c.color_bg, v_c.color_bg)),
      pgv.stat('Main', pgv.badge(v_c.color_main, v_c.color_main)),
      pgv.stat('Accent', pgv.badge(v_c.color_accent, v_c.color_accent)),
      pgv.stat('Text', pgv.badge(v_c.color_text, v_c.color_text)),
      pgv.stat('Text light', pgv.badge(v_c.color_text_light, v_c.color_text_light)),
      pgv.stat('Border', pgv.badge(v_c.color_border, v_c.color_border))
    ]);

  -- Color extra
  IF v_c.color_extra != '{}'::jsonb THEN
    v_body := v_body || '<h4>Couleurs libres</h4><p>';
    FOR v_k, v_v IN SELECT key, value #>> '{}' FROM jsonb_each(v_c.color_extra)
    LOOP
      v_body := v_body || pgv.badge(v_k || ' ' || v_v, v_v) || ' ';
    END LOOP;
    v_body := v_body || '</p>';
  END IF;

  -- Fonts
  v_body := v_body || '<h3>Typographie</h3>'
    || pgv.grid(VARIADIC ARRAY[
      pgv.stat('Heading', pgv.esc(v_c.font_heading)),
      pgv.stat('Body', pgv.esc(v_c.font_body))
    ]);

  -- Spacing
  IF v_c.spacing_page IS NOT NULL OR v_c.spacing_section IS NOT NULL THEN
    v_body := v_body || '<h3>Spacing</h3>'
      || pgv.grid(VARIADIC ARRAY[
        pgv.stat('Page', COALESCE(v_c.spacing_page, '—')),
        pgv.stat('Section', COALESCE(v_c.spacing_section, '—')),
        pgv.stat('Gap', COALESCE(v_c.spacing_gap, '—')),
        pgv.stat('Card', COALESCE(v_c.spacing_card, '—'))
      ]);
  END IF;

  -- Shadow / Radius
  IF v_c.shadow_card IS NOT NULL OR v_c.radius_card IS NOT NULL THEN
    v_body := v_body || '<h3>Shadow / Radius</h3>'
      || pgv.grid(VARIADIC ARRAY[
        pgv.stat('Card shadow', COALESCE(v_c.shadow_card, '—')),
        pgv.stat('Elevated shadow', COALESCE(v_c.shadow_elevated, '—')),
        pgv.stat('Card radius', COALESCE(v_c.radius_card, '—'))
      ]);
  END IF;

  -- Voice
  IF v_c.voice_personality IS NOT NULL THEN
    v_body := v_body || '<h3>Voice</h3><p>'
      || '<strong>Personnalité:</strong> ' || array_to_string(v_c.voice_personality, ', ') || '<br>'
      || '<strong>Formalité:</strong> ' || COALESCE(v_c.voice_formality, '—')
      || '</p>';
    IF v_c.voice_do IS NOT NULL THEN
      v_body := v_body || '<p><strong>Do:</strong> ' || array_to_string(v_c.voice_do, ', ') || '</p>';
    END IF;
    IF v_c.voice_dont IS NOT NULL THEN
      v_body := v_body || '<p><strong>Don''t:</strong> ' || array_to_string(v_c.voice_dont, ', ') || '</p>';
    END IF;
  END IF;

  -- Actions
  v_body := v_body || '<p>'
    || pgv.action('post_charte_delete', pgv.t('docs.btn_delete'), jsonb_build_object('p_id', v_c.id), 'Supprimer cette charte ?', 'danger')
    || '</p>';

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION docs.get_charte(text) IS 'pgView page: charte detail with all tokens, voice, rules';

CREATE OR REPLACE FUNCTION docs.get_chartes()
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_body text;
  v_rows text[];
  v_cnt int;
  r record;
BEGIN
  SELECT count(*)::int INTO v_cnt FROM docs.charte WHERE tenant_id = current_setting('app.tenant_id', true);

  v_body := '<h2>' || pgv.t('docs.title_chartes') || '</h2>';

  IF v_cnt = 0 THEN
    RETURN v_body || pgv.empty(pgv.t('docs.empty_no_chartes'), pgv.t('docs.empty_first_charte'));
  END IF;

  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT id, name, description, color_bg, color_main, color_accent, font_heading, font_body,
           (SELECT count(*) FROM docs.document d WHERE d.charte_id = c.id) AS doc_cnt
    FROM docs.charte c
    WHERE tenant_id = current_setting('app.tenant_id', true)
    ORDER BY name
  LOOP
    v_rows := v_rows || ARRAY[
      format('<a href="/charte?p_id=%s">%s</a>', r.id, pgv.esc(r.name)),
      COALESCE(r.description, '—'),
      pgv.badge(' ', r.color_bg) || ' ' || pgv.badge(' ', r.color_main) || ' ' || pgv.badge(' ', r.color_accent),
      r.font_heading || ' / ' || r.font_body,
      r.doc_cnt::text
    ];
  END LOOP;

  v_body := v_body || pgv.md_table(
    ARRAY[pgv.t('docs.col_name'), 'Description', pgv.t('docs.col_colors'), pgv.t('docs.col_fonts'), 'Docs'],
    v_rows, 20
  );

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION docs.get_chartes() IS 'pgView page: list chartes with color preview cards';

CREATE OR REPLACE FUNCTION docs.get_document(p_id text)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_d docs.document;
  v_body text;
  v_charte_name text;
  v_rows text[];
  r record;
BEGIN
  SELECT * INTO v_d FROM docs.document WHERE id = p_id AND tenant_id = current_setting('app.tenant_id', true);
  IF v_d IS NULL THEN RETURN pgv.empty(pgv.t('docs.err_not_found')); END IF;

  IF v_d.charte_id IS NOT NULL THEN
    SELECT name INTO v_charte_name FROM docs.charte WHERE id = v_d.charte_id;
  END IF;

  v_body := pgv.breadcrumb(VARIADIC ARRAY[pgv.t('docs.brand'), '/', pgv.esc(v_d.name)]);

  v_body := v_body || '<p><small>'
    || v_d.format || ' ' || v_d.orientation
    || ' · ' || v_d.width::int::text || '×' || v_d.height::int::text
    || ' · ' || pgv.badge(v_d.status, CASE v_d.status WHEN 'draft' THEN 'secondary' WHEN 'generated' THEN 'primary' WHEN 'signed' THEN 'success' ELSE 'muted' END)
    || CASE WHEN v_charte_name IS NOT NULL THEN ' · Charte: ' || pgv.esc(v_charte_name) ELSE '' END
    || '</small></p>';

  -- Pages table
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT page_index, name, length(html) AS html_len,
           (SELECT count(*)::int FROM regexp_matches(html, 'data-id="[^"]*"', 'g')) AS elem_cnt
    FROM docs.page WHERE doc_id = p_id ORDER BY page_index
  LOOP
    v_rows := v_rows || ARRAY[
      r.page_index::text,
      pgv.esc(r.name),
      r.elem_cnt::text,
      pg_size_pretty(r.html_len::bigint)
    ];
  END LOOP;

  IF cardinality(v_rows) > 0 THEN
    v_body := v_body || '<h3>Pages</h3>'
      || pgv.md_table(ARRAY['#', 'Nom', 'Éléments', 'Taille'], v_rows, 20);
  END IF;

  -- Actions
  v_body := v_body || '<p>'
    || '<a href="' || pgv.call_ref('get_print', jsonb_build_object('p_id', p_id)) || '" target="_blank"><button class="outline">Imprimer</button></a> '
    || pgv.action('post_document_duplicate', pgv.t('docs.btn_duplicate'), jsonb_build_object('p_source_id', p_id), 'Dupliquer ce document ?', 'outline')
    || ' '
    || pgv.action('post_document_delete', pgv.t('docs.btn_delete'), jsonb_build_object('p_id', p_id), 'Supprimer ce document et toutes ses pages ?', 'danger')
    || '</p>';

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION docs.get_document(text) IS 'pgView page: document detail with pages, charte, print/duplicate/delete actions';

CREATE OR REPLACE FUNCTION docs.get_index()
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_body text;
  v_nb_docs int;
  v_nb_chartes int;
  v_nb_pages int;
  v_nb_draft int;
  v_rows text[];
  r record;
BEGIN
  -- Stats
  SELECT count(*)::int INTO v_nb_docs FROM docs.document;
  SELECT count(*)::int INTO v_nb_chartes FROM docs.charte;
  SELECT count(*)::int INTO v_nb_pages FROM docs.page;
  SELECT count(*)::int INTO v_nb_draft FROM docs.document WHERE status = 'draft';

  v_body := pgv.grid(VARIADIC ARRAY[
    pgv.stat(pgv.t('docs.stat_documents'), v_nb_docs::text),
    pgv.stat(pgv.t('docs.stat_chartes'), v_nb_chartes::text),
    pgv.stat(pgv.t('docs.stat_pages'), v_nb_pages::text),
    pgv.stat(pgv.t('docs.stat_draft'), v_nb_draft::text)
  ]);

  -- Document list
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT d.id, d.name, d.category, d.format, d.orientation, d.status,
           c.name AS charte_name,
           (SELECT count(*) FROM docs.page p WHERE p.doc_id = d.id) AS nb_pages,
           d.updated_at
    FROM docs.document d
    LEFT JOIN docs.charte c ON c.id = d.charte_id
    ORDER BY d.updated_at DESC
  LOOP
    v_rows := v_rows || ARRAY[
      format('<a href="/document?p_id=%s">%s</a>', r.id, pgv.esc(r.name)),
      r.category,
      r.format || ' ' || r.orientation,
      COALESCE(r.charte_name, '—'),
      pgv.badge(r.status, CASE r.status WHEN 'draft' THEN 'secondary' WHEN 'generated' THEN 'primary' WHEN 'signed' THEN 'success' ELSE 'muted' END),
      r.nb_pages::text,
      to_char(r.updated_at, 'DD/MM/YY')
    ];
  END LOOP;

  IF v_nb_docs = 0 THEN
    v_body := v_body || pgv.empty(pgv.t('docs.empty_no_documents'), pgv.t('docs.empty_first_document'));
  ELSE
    v_body := v_body || pgv.md_table(
      ARRAY[pgv.t('docs.col_name'), pgv.t('docs.col_category'), pgv.t('docs.col_format'), pgv.t('docs.col_charte'), pgv.t('docs.col_status'), pgv.t('docs.col_pages'), pgv.t('docs.col_updated')],
      v_rows, 20
    );
  END IF;

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION docs.get_index() IS 'Document dashboard — stats chartes/documents, document list with status';

CREATE OR REPLACE FUNCTION docs.get_libraries()
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_body text;
  v_rows text[];
  v_cnt int;
  r record;
BEGIN
  SELECT count(*)::int INTO v_cnt FROM docs.library WHERE tenant_id = current_setting('app.tenant_id', true);

  v_body := '<h2>' || pgv.t('docs.title_libraries') || '</h2>';

  IF v_cnt = 0 THEN
    RETURN v_body || pgv.empty(pgv.t('docs.empty_no_libraries'), pgv.t('docs.empty_first_library'));
  END IF;

  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT l.id, l.name, l.description,
           (SELECT count(*) FROM docs.library_asset la WHERE la.library_id = l.id) AS asset_cnt,
           (SELECT count(*) FROM docs.document d WHERE d.library_id = l.id) AS doc_cnt
    FROM docs.library l
    WHERE l.tenant_id = current_setting('app.tenant_id', true)
    ORDER BY l.name
  LOOP
    v_rows := v_rows || ARRAY[
      format('<a href="/library?p_id=%s">%s</a>', r.id, pgv.esc(r.name)),
      COALESCE(r.description, '—'),
      r.asset_cnt::text,
      r.doc_cnt::text
    ];
  END LOOP;

  v_body := v_body || pgv.md_table(
    ARRAY[pgv.t('docs.col_name'), 'Description', 'Assets', 'Docs'],
    v_rows, 20
  );

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION docs.get_libraries() IS 'pgView page: list libraries with asset count';

CREATE OR REPLACE FUNCTION docs.get_library(p_id text)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_lib docs.library;
  v_body text;
  v_rows text[];
  r record;
BEGIN
  SELECT * INTO v_lib FROM docs.library WHERE id = p_id AND tenant_id = current_setting('app.tenant_id', true);
  IF v_lib IS NULL THEN RETURN pgv.empty('Photothèque introuvable'); END IF;

  v_body := pgv.breadcrumb(VARIADIC ARRAY[pgv.t('docs.brand'), '/libraries', pgv.esc(v_lib.name)]);

  IF v_lib.description IS NOT NULL THEN
    v_body := v_body || '<p>' || pgv.esc(v_lib.description) || '</p>';
  END IF;

  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT a.filename, a.title, a.mime_type, a.width, a.height,
           la.role, la.context, la.sort_order
    FROM docs.library_asset la
    JOIN asset.asset a ON a.id = la.asset_id
    WHERE la.library_id = p_id
    ORDER BY la.sort_order, a.filename
  LOOP
    v_rows := v_rows || ARRAY[
      r.sort_order::text,
      pgv.esc(r.filename),
      COALESCE(r.title, '—'),
      COALESCE(r.role, '—'),
      COALESCE(r.context, '—'),
      r.mime_type,
      CASE WHEN r.width IS NOT NULL THEN r.width::text || '×' || r.height::text ELSE '—' END
    ];
  END LOOP;

  IF cardinality(v_rows) > 0 THEN
    v_body := v_body || '<h3>Assets</h3>'
      || pgv.md_table(ARRAY['#', 'Fichier', 'Titre', 'Rôle', 'Contexte', 'Type', 'Dimensions'], v_rows, 20);
  ELSE
    v_body := v_body || pgv.empty('Aucun asset dans cette photothèque');
  END IF;

  v_body := v_body || '<p>'
    || pgv.action('post_library_delete', pgv.t('docs.btn_delete'), jsonb_build_object('p_id', v_lib.id), 'Supprimer cette photothèque ?', 'danger')
    || '</p>';

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION docs.get_library(text) IS 'pgView page: library detail with asset list';

CREATE OR REPLACE FUNCTION docs.get_print(p_id text)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_d docs.document;
  v_charte_css text := '';
  v_print_css text;
  v_body text;
  r record;
BEGIN
  SELECT * INTO v_d FROM docs.document WHERE id = p_id AND tenant_id = current_setting('app.tenant_id', true);
  IF v_d IS NULL THEN RETURN pgv.empty(pgv.t('docs.err_not_found')); END IF;

  IF v_d.charte_id IS NOT NULL THEN
    v_charte_css := docs.charte_tokens_to_css(v_d.charte_id);
  END IF;

  v_print_css := docs.document_print_css(p_id);

  v_body := '<style>' || v_charte_css || chr(10) || v_print_css || '</style>';

  FOR r IN
    SELECT page_index, html, bg,
           COALESCE(width, v_d.width) AS w,
           COALESCE(height, v_d.height) AS h
    FROM docs.page WHERE doc_id = p_id ORDER BY page_index
  LOOP
    v_body := v_body || '<div class="doc-print-page" style="width:' || r.w::text || 'mm;height:' || r.h::text || 'mm;'
      || 'background:' || COALESCE(r.bg, v_d.bg) || '">'
      || r.html
      || '</div>';
  END LOOP;

  v_body := v_body || '<script>window.print()</script>';

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION docs.get_print(text) IS 'Print-ready page: charte CSS + print CSS + all pages stacked + auto-print';

